INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-medical-and-charity-support-directory', 'resources', 'medical-and-charity-support-directory', 'Medical and charity support directory', 'A careful directory placeholder for charitable medical aid, seva networks, and emergency support references connected with Jain organizations.', 'A careful directory placeholder for charitable medical aid, seva networks, and emergency support references connected with Jain organizations. Support rules depend on the trust, hospital partner, fund criteria, and local verification requirements. Helps families identify possible support channels that must still be verified directly with the relevant trust or provider. Medical records, identity proof, income proof, recommendation letters, or hospital documents may be required. Medical / Charity Support India / Global', '/resources.html', 'Medical / Charity Support', 'India / Global', 'en', 'published', 'pending_review', 'Directory in progress', '2026-05-25', '2026-05-25', 5, '2026-05-25');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-how-to-verify-government-scheme-eligibility', 'resources', 'how-to-verify-government-scheme-eligibility', 'How to verify government scheme eligibility', 'A step-by-step guide to checking whether a scheme is current, whether it applies to your category or state, and whether the website or circular is official.', 'A step-by-step guide to checking whether a scheme is current, whether it applies to your category or state, and whether the website or circular is official. Useful for applicants, volunteers, and family members helping someone review a scheme. Reduces confusion by encouraging users to confirm current notifications, deadlines, and official portals before applying. No fixed documents for the guide itself. Use the relevant official notice to confirm application requirements. Government Scheme India', '/resources.html', 'Government Scheme', 'India', 'en', 'published', 'verified', 'JainWorld reviewed guide', '2026-05-25', '2026-05-25', 5, '2026-05-25');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-report-resource-update-or-correction', 'resources', 'report-resource-update-or-correction', 'Report a resource update or correction', 'Use this entry to report a broken link, changed eligibility note, outdated deadline reference, or a missing official source.', 'Use this entry to report a broken link, changed eligibility note, outdated deadline reference, or a missing official source. Open to users, students, families, institutions, and contributors who notice an issue. Helps keep public resource pages more accurate over time. Please share the page title, issue, and the best official source link if available. Documents / How-to Guide Global', '/resources.html', 'Documents / How-to Guide', 'Global', 'en', 'published', 'verified', 'JainWorld corrections workflow', '2026-05-25', '2026-05-25', 5, '2026-05-25');
